SELECT MAX(performance_value) AS max_output_value
FROM equipment_performance
WHERE performance_metric = 'output' AND measurement_unit = 'MW';

SELECT equipment_id, COUNT(maintenance_id) AS maintenance_count
FROM maintenance_schedules
GROUP BY equipment_id;

SELECT ambient_pressure_millibar
FROM ambient_pressure_readings
WHERE ambient_pressure_millibar > 1020;

SELECT hourly_energy_output_mw 
FROM hourly_energy_output_readings 
WHERE hourly_energy_output_id = 0;

SELECT reading_id, hourly_energy_output_id, ROUND(hourly_energy_output_mw, 2) AS rounded_output
FROM hourly_energy_output_readings
WHERE hourly_energy_output_mw > 400;
